<template><main class="page"><div class="grid"><div class="canvas-wrap"><GameCanvas /><div v-if="game.isReplaying" class="replay-overlay"><div class="replay-content"><div class="replay-title">死亡回放</div><div class="replay-progress"><div class="replay-progress-bar" :style="{ width: replayProgress + '%' }"></div></div><GameButton @click="game.skipDeathReplay">跳过回放</GameButton></div></div></div><div class="grid"><LeaderboardPanel :rows="game.state?.leaderboards || []" /><CombatLog /><GameButton v-if="!game.isReplaying" @click="game.toggleObserver">{{ game.observer ? '退出观战' : '观战切换' }}</GameButton></div></div></main></template><script setup lang="ts">import { computed, onMounted } from 'vue'; import { useRoute } from 'vue-router'; import { useGameStore } from '../stores/gameStore'; import GameCanvas from '../components/common/GameCanvas.vue'; import LeaderboardPanel from '../components/common/LeaderboardPanel.vue'; import CombatLog from '../components/common/CombatLog.vue'; import GameButton from '../components/common/GameButton.vue'; const route=useRoute(); const game=useGameStore(); const replayProgress=computed(()=>{ if(!game.isReplaying||game.replayFrames.length===0) return 0; return Math.min(100,Math.floor((game.replayFrameIndex/game.replayFrames.length)*100)); }); onMounted(()=>{ if(!game.state) game.start(String(route.params.id)); });</script><style scoped>.canvas-wrap{position:relative;display:inline-block;}.replay-overlay{position:absolute;top:0;left:0;right:0;bottom:0;background:rgba(0,0,0,0.4);display:flex;align-items:flex-start;justify-content:center;padding-top:20px;pointer-events:none;}.replay-content{display:flex;flex-direction:column;align-items:center;gap:12px;background:rgba(0,0,0,0.7);padding:16px 24px;border-radius:12px;color:#fff;pointer-events:auto;}.replay-title{font-size:18px;font-weight:600;}.replay-progress{width:200px;height:8px;background:#333;border-radius:4px;overflow:hidden;}.replay-progress-bar{height:100%;background:#f2c94c;transition:width 0.1s linear;}</style>
